"use client"

import { CalendarRoot as InternalCalendarScheduler } from "./internal/elements/root"
import { mergeCalendarClassNames } from "./internal/utils/class-names"
import type { CalendarRootProps as CalendarSchedulerProps } from "./internal/shared"
import type { CalendarClassNames } from "./types"

const starterSelectedEventClassNames = {
  agendaEvent:
    "data-[selected=true]:border-ring data-[selected=true]:ring-2 data-[selected=true]:ring-ring/60",
  monthEvent:
    "data-[selected=true]:border-ring data-[selected=true]:ring-2 data-[selected=true]:ring-ring/60",
  timeGridEvent:
    "data-[selected=true]:border-ring data-[selected=true]:ring-2 data-[selected=true]:ring-ring/60",
} satisfies CalendarClassNames

export function CalendarScheduler({
  classNames,
  ...props
}: CalendarSchedulerProps) {
  return (
    <InternalCalendarScheduler
      {...props}
      classNames={mergeCalendarClassNames(
        starterSelectedEventClassNames,
        classNames
      )}
    />
  )
}

export type { CalendarSchedulerProps }

import { calendarSlots, type CalendarClassNames } from "../../types"
import { cn } from "../lib/utils"

export function mergeCalendarClassNames(
  ...classNameSets: Array<CalendarClassNames | undefined>
) {
  const mergedClassNames: CalendarClassNames = {}

  for (const slot of calendarSlots) {
    const slotClassName = cn(
      classNameSets.map((classNames) => classNames?.[slot])
    )

    if (slotClassName) {
      mergedClassNames[slot] = slotClassName
    }
  }

  return Object.keys(mergedClassNames).length > 0 ? mergedClassNames : undefined
}

import * as React from "react"

import type { CalendarEvent } from "../../types"
import {
  getCalendarSlotClassName,
  intervalOverlapsBlockedRanges,
  normalizeAvailableViews,
  normalizeHiddenDays,
  resolveCalendarView,
} from "../../utils"
import { CalendarAgendaView } from "./agenda-view"
import { CalendarMonthView } from "./month-view"
import { CalendarToolbar } from "./toolbar"
import { CalendarDayView, CalendarWeekView } from "./time-grid-view"
import {
  compactSlotHeight,
  defaultMaxHour,
  defaultMinHour,
  defaultSlotDuration,
  slotHeight as defaultSlotHeight,
  type CalendarRootProps,
} from "../shared"
import { CalendarRootPortals } from "./root/calendar/portals"
import { getCalendarSurfaceShadowClassName } from "./root/root-utils"
import { useCalendarDerivedState } from "./root/use-calendar-derived-state"
import { useCalendarEventActions } from "./root/use-calendar-event-actions"
import { useCalendarPointerInteractions } from "./root/use-calendar-pointer-interactions"

export function CalendarRoot({
  agendaDays = 14,
  availableViews,
  blockedRanges,
  businessHours,
  classNames,
  createEventSheet,
  date,
  density = "comfortable",
  eventChangeConfirmation,
  eventDetails,
  events,
  getEventColor,
  hiddenDays,
  hourCycle,
  keyboardShortcuts,
  locale,
  maxHour = defaultMaxHour,
  minHour = defaultMinHour,
  onDateChange,
  onEventArchive,
  onEventCreate,
  onEventDelete,
  onEventDuplicate,
  onEventMove,
  onEventResize,
  onEventSelect,
  onEventUpdate,
  onNavigate,
  onResourceFilterChange,
  onSelectedEventChange,
  onToday,
  onViewChange,
  renderEmptyState,
  renderEvent,
  renderEventDetails,
  renderToolbarExtras,
  resources,
  resourceFilter,
  scrollToTime,
  secondaryTimeZone,
  selectedEventId,
  showCreatePreviewMeta = true,
  showDragPreviewMeta = true,
  showSecondaryTimeZone = false,
  slotDuration = defaultSlotDuration,
  slotHeight: customSlotHeight,
  surfaceShadow = "none",
  defaultResourceFilter,
  timeZone,
  view,
  weekStartsOn = 1,
}: CalendarRootProps) {
  const [optimisticEvents, setOptimisticEvents] =
    React.useState<CalendarEvent[]>(events)
  const [isHydrated, setIsHydrated] = React.useState(false)
  const allResourceIds = React.useMemo(
    () => resources?.map((resource) => resource.id) ?? [],
    [resources]
  )
  const [internalResourceFilter, setInternalResourceFilter] = React.useState<
    string[]
  >(() => defaultResourceFilter ?? allResourceIds)
  const resolvedAvailableViews = React.useMemo(
    () => normalizeAvailableViews(availableViews),
    [availableViews]
  )
  const resolvedHiddenDays = React.useMemo(
    () => normalizeHiddenDays(hiddenDays),
    [hiddenDays]
  )
  const resolvedView = React.useMemo(
    () => resolveCalendarView(view, resolvedAvailableViews),
    [resolvedAvailableViews, view]
  )
  const resolvedSlotHeight =
    customSlotHeight ??
    (density === "compact" ? compactSlotHeight : defaultSlotHeight)
  const resolvedResourceFilter = React.useMemo(() => {
    const nextFilter = resourceFilter ?? internalResourceFilter
    const dedupedFilter = Array.from(new Set(nextFilter)).filter((id) =>
      allResourceIds.includes(id)
    )

    if (allResourceIds.length === 0) {
      return dedupedFilter
    }

    return dedupedFilter.length > 0 ? dedupedFilter : allResourceIds
  }, [allResourceIds, internalResourceFilter, resourceFilter])
  const keyboardShortcutsTrigger =
    typeof keyboardShortcuts === "object"
      ? (keyboardShortcuts.trigger ?? "both")
      : keyboardShortcuts
        ? "both"
        : null
  const keyboardShortcutsButtonLabel =
    typeof keyboardShortcuts === "object"
      ? (keyboardShortcuts.buttonLabel ?? "Shortcuts")
      : "Shortcuts"
  const showKeyboardShortcutsButton =
    keyboardShortcutsTrigger === "both" ||
    keyboardShortcutsTrigger === "button"

  React.useEffect(() => {
    setIsHydrated(true)
  }, [])

  React.useLayoutEffect(() => {
    setOptimisticEvents(events)
  }, [events])

  React.useEffect(() => {
    setInternalResourceFilter((currentFilter) => {
      if (resourceFilter) {
        return currentFilter
      }

      const nextFilter =
        currentFilter.length > 0
          ? currentFilter.filter((id) => allResourceIds.includes(id))
          : defaultResourceFilter ?? allResourceIds

      return nextFilter.length > 0 || allResourceIds.length === 0
        ? nextFilter
        : allResourceIds
    })
  }, [allResourceIds, defaultResourceFilter, resourceFilter])

  const setActiveResourceIds = React.useCallback(
    (nextResourceIds: string[]) => {
      const dedupedResourceIds = Array.from(new Set(nextResourceIds)).filter((id) =>
        allResourceIds.includes(id)
      )

      if (!resourceFilter) {
        setInternalResourceFilter(dedupedResourceIds)
      }

      onResourceFilterChange?.(dedupedResourceIds)
    },
    [allResourceIds, onResourceFilterChange, resourceFilter]
  )

  const shouldBlockTimedRange = React.useCallback(
    (start: Date, end: Date, allDay: boolean | undefined) => {
      if (
        allDay ||
        resolvedView === "month" ||
        resolvedView === "agenda" ||
        !blockedRanges?.length
      ) {
        return false
      }

      return intervalOverlapsBlockedRanges(start, end, blockedRanges)
    },
    [blockedRanges, resolvedView]
  )

  const actions = useCalendarEventActions({
    createEventSheet,
    date,
    eventChangeConfirmation,
    eventDetails,
    hourCycle,
    isHydrated,
    keyboardShortcuts,
    locale,
    minHour,
    onDateChange,
    onEventArchive,
    onEventCreate,
    onEventDelete,
    onEventDuplicate,
    onEventMove,
    onEventResize,
    onEventSelect,
    onEventUpdate,
    onNavigate,
    onSelectedEventChange,
    onToday,
    optimisticEvents,
    resolvedHiddenDays,
    resolvedResourceFilter,
    resolvedView,
    resources,
    setOptimisticEvents,
    shouldBlockTimedRange,
    slotDuration,
    timeZone,
  })

  const pointer = useCalendarPointerInteractions({
    announce: actions.announce,
    closeContextMenu: actions.closeContextMenu,
    closeEventDetails: actions.closeEventDetails,
    enableEventMove: !!onEventMove,
    enableEventResize: !!onEventResize,
    moveOccurrenceWithTarget: actions.moveOccurrenceWithTarget,
    resizeOccurrenceWithTarget: actions.resizeOccurrenceWithTarget,
    selectOccurrence: (occurrence) => {
      actions.handleSelectEvent(occurrence)
    },
  })

  const derived = useCalendarDerivedState({
    activeDrag: pointer.activeDrag,
    activeDragOffsetMinutes: pointer.activeDragOffsetMinutes,
    activeDropTarget: pointer.activeDropTarget,
    activeResize: pointer.activeResize,
    activeResizeTarget: pointer.activeResizeTarget,
    agendaDays,
    blockedRanges,
    businessHours,
    classNames,
    clearResourceFilter: () => setActiveResourceIds(allResourceIds),
    date,
    density,
    getEventColor,
    handleEventCreateRequest: onEventCreate
      ? actions.requestEventCreate
      : undefined,
    handleEventDragPointerDown: pointer.handleEventDragPointerDown,
    handleEventKeyCommand: actions.handleEventKeyCommand,
    handleOpenContextMenu: actions.handleOpenContextMenu,
    handleResizeHandlePointerDown: pointer.handleResizeHandlePointerDown,
    handleSelectEvent: (occurrence) => {
      actions.handleSelectEvent(occurrence)
    },
    hourCycle,
    isHydrated,
    isPointerDragging: pointer.isPointerDragging,
    locale,
    optimisticEvents,
    renderEmptyState,
    renderEvent,
    resolvedHiddenDays,
    resolvedResourceFilter,
    resolvedSlotHeight,
    resolvedView,
    resources,
    scrollToTime,
    secondaryTimeZone,
    selectedEventId,
    shouldBlockTimedRange,
    shouldSuppressEventClick: pointer.shouldSuppressEventClick,
    showCreatePreviewMeta,
    showDragPreviewMeta,
    showSecondaryTimeZone,
    slotDuration,
    timeZone,
    weekStartsOn,
  })
  const detailsOccurrence = actions.detailsOccurrence
  const setDetailsOccurrence = actions.setDetailsOccurrence

  React.useEffect(() => {
    if (
      selectedEventId &&
      !derived.occurrences.some(
        (occurrence) => occurrence.occurrenceId === selectedEventId
      )
    ) {
      onSelectedEventChange?.(undefined)
    }

    if (
      detailsOccurrence &&
      !derived.occurrences.some(
        (occurrence) => occurrence.occurrenceId === detailsOccurrence.occurrenceId
      )
    ) {
      setDetailsOccurrence(null)
    }
  }, [
    detailsOccurrence,
    derived.occurrences,
    onSelectedEventChange,
    setDetailsOccurrence,
    selectedEventId,
  ])

  return (
    <div
      className={getCalendarSlotClassName(
        classNames,
        "root",
        "flex min-h-[42rem] flex-col overflow-hidden rounded-[calc(var(--radius)*1.6)] border border-border/70 bg-background",
        getCalendarSurfaceShadowClassName(surfaceShadow)
      )}
      data-testid="calendar-root"
    >
      <CalendarToolbar
        activeResourceIds={resolvedResourceFilter}
        availableViews={resolvedAvailableViews}
        classNames={classNames}
        currentLabel={derived.currentLabel}
        density={density}
        keyboardShortcutsButtonLabel={keyboardShortcutsButtonLabel}
        onNavigate={actions.handleNavigate}
        onOpenKeyboardShortcuts={
          showKeyboardShortcutsButton
            ? () => actions.setIsKeyboardShortcutsOpen(true)
            : undefined
        }
        onQuickCreate={onEventCreate ? actions.handleQuickCreate : undefined}
        onResourceFilterChange={
          resources?.length && resources.length > 1 ? setActiveResourceIds : undefined
        }
        onToday={actions.handleToday}
        onViewChange={onViewChange}
        renderToolbarExtras={renderToolbarExtras}
        resources={resources}
        secondaryTimeZone={secondaryTimeZone}
        showSecondaryTimeZone={showSecondaryTimeZone}
        timeZone={timeZone}
        view={resolvedView}
      />
      <div
        className={getCalendarSlotClassName(
          classNames,
          "shell",
          "relative flex min-h-0 flex-1 flex-col bg-background"
        )}
      >
        {resolvedView === "month" ? (
          <CalendarMonthView {...derived.sharedViewProps} />
        ) : null}
        {resolvedView === "week" ? (
          <CalendarWeekView
            {...derived.sharedViewProps}
            maxHour={maxHour}
            minHour={minHour}
          />
        ) : null}
        {resolvedView === "day" ? (
          <CalendarDayView
            {...derived.sharedViewProps}
            maxHour={maxHour}
            minHour={minHour}
          />
        ) : null}
        {resolvedView === "agenda" ? (
          <CalendarAgendaView
            {...derived.sharedViewProps}
            range={derived.range}
          />
        ) : null}
        {derived.occurrences.length === 0 ? (
          <div className="pointer-events-none absolute inset-x-4 bottom-4 z-20 flex justify-center">
            <div className="pointer-events-auto max-w-md rounded-[calc(var(--radius)*1.1)] border border-border/70 bg-background/95 px-4 py-3 text-center shadow-lg backdrop-blur-sm">
              {derived.emptyStateContent ?? (
                <>
                  <p className="font-medium">No events match this view.</p>
                  <p className="mt-1 text-sm text-muted-foreground">
                    Adjust the resource filters or create a new event to start
                    filling the schedule.
                  </p>
                </>
              )}
            </div>
          </div>
        ) : null}
      </div>
      <CalendarRootPortals
        activeDrag={pointer.activeDrag}
        activeDragInteraction={pointer.activeDragInteraction}
        activeDragRect={pointer.activeDragRect}
        classNames={classNames}
        closeContextMenu={actions.closeContextMenu}
        closeCreateSheet={actions.closeCreateSheet}
        closeEventDetails={actions.closeEventDetails}
        closePendingEventChange={actions.closePendingEventChange}
        commitCreateEvent={actions.commitCreateEvent}
        commitEventUpdate={actions.commitEventUpdate}
        contextMenu={actions.contextMenu}
        createEventSheet={createEventSheet}
        createSheetOperation={actions.createSheetOperation}
        density={density}
        detailsOccurrence={detailsOccurrence}
        eventChangeConfirmation={eventChangeConfirmation}
        eventDetails={eventDetails}
        eventDetailsEnabled={actions.eventDetailsEnabled}
        getEventColor={getEventColor}
        handleArchiveEvent={actions.handleArchiveEvent}
        handleConfirmPendingEventChange={actions.handleConfirmPendingEventChange}
        handleDeleteEvent={actions.handleDeleteEvent}
        handleDuplicateEvent={actions.handleDuplicateEvent}
        hourCycle={hourCycle}
        isHydrated={isHydrated}
        isKeyboardShortcutsOpen={actions.isKeyboardShortcutsOpen}
        isPointerDragging={pointer.isPointerDragging}
        keyboardShortcuts={keyboardShortcuts}
        locale={locale}
        onEventArchive={onEventArchive}
        onEventDelete={onEventDelete}
        onEventDuplicate={onEventDuplicate}
        onEventUpdate={onEventUpdate}
        openEventDetails={actions.openEventDetails}
        pendingEventChange={actions.pendingEventChange}
        renderEvent={renderEvent}
        renderEventDetails={renderEventDetails}
        resources={resources}
        secondaryTimeZone={secondaryTimeZone}
        setIsKeyboardShortcutsOpen={actions.setIsKeyboardShortcutsOpen}
        shouldSuppressEventClick={pointer.shouldSuppressEventClick}
        showDragPreviewMeta={showDragPreviewMeta}
        showSecondaryTimeZone={showSecondaryTimeZone}
        timeZone={timeZone}
      />
      <p
        aria-live="polite"
        className="sr-only"
        data-testid="calendar-live-announcement"
      >
        {actions.liveAnnouncement}
      </p>
    </div>
  )
}

import { createPortal } from "react-dom"

import type {
  CalendarCreateOperation,
  CalendarDragData,
  CalendarEvent,
  CalendarEventChangeConfirmationContext,
  CalendarOccurrence,
  CalendarResource,
} from "../../../../types"
import {
  canArchiveOccurrence,
  canDeleteOccurrence,
  canDuplicateOccurrence,
  canOpenEventDetails,
  formatDurationLabel,
  getCalendarSlotClassName,
  getEventMetaLabel,
} from "../../../../utils"
import type {
  CalendarEventMenuPosition,
  CalendarRootProps,
} from "../../../shared"
import { EventSurface, getResolvedAccentColor } from "../../event-card"
import { CalendarEventChangeConfirmationDialog } from "../../event-change-confirmation-dialog"
import { CalendarEventContextMenu } from "../../event-context-menu"
import { CalendarEventCreateSheet } from "../../event-create-sheet"
import { CalendarEventDetailsSheet } from "../../event-details-sheet"
import { CalendarKeyboardShortcutsDialog } from "../../keyboard-shortcuts-dialog"

import {
  getDragOverlayStyle,
  type ActiveDragInteraction,
} from "../root-utils"

type CalendarRootPortalsProps = {
  activeDrag: CalendarDragData | null
  activeDragInteraction: ActiveDragInteraction | null
  activeDragRect: DOMRect | null
  classNames: CalendarRootProps["classNames"]
  closeContextMenu: () => void
  closeCreateSheet: () => void
  closeEventDetails: () => void
  closePendingEventChange: () => void
  commitCreateEvent: (operation: CalendarCreateOperation) => string | void
  commitEventUpdate: (nextEvent: CalendarEvent) => void
  contextMenu: {
    occurrence: CalendarOccurrence
    position: CalendarEventMenuPosition
  } | null
  createEventSheet: CalendarRootProps["createEventSheet"]
  createSheetOperation: CalendarCreateOperation | null
  density: CalendarRootProps["density"]
  detailsOccurrence: CalendarOccurrence | null
  eventChangeConfirmation: CalendarRootProps["eventChangeConfirmation"]
  eventDetails: CalendarRootProps["eventDetails"]
  eventDetailsEnabled: boolean
  getEventColor?: CalendarRootProps["getEventColor"]
  handleArchiveEvent: (occurrence: CalendarOccurrence) => void
  handleConfirmPendingEventChange: () => void
  handleDeleteEvent: (occurrence: CalendarOccurrence) => void
  handleDuplicateEvent: (occurrence: CalendarOccurrence) => void
  hourCycle?: 12 | 24
  isHydrated: boolean
  isKeyboardShortcutsOpen: boolean
  isPointerDragging: boolean
  keyboardShortcuts: CalendarRootProps["keyboardShortcuts"]
  locale?: string
  onEventArchive?: CalendarRootProps["onEventArchive"]
  onEventDelete?: CalendarRootProps["onEventDelete"]
  onEventDuplicate?: CalendarRootProps["onEventDuplicate"]
  onEventUpdate?: CalendarRootProps["onEventUpdate"]
  openEventDetails: (occurrence: CalendarOccurrence) => void
  pendingEventChange: CalendarEventChangeConfirmationContext | null
  renderEvent: CalendarRootProps["renderEvent"]
  renderEventDetails: CalendarRootProps["renderEventDetails"]
  resources?: CalendarResource[]
  secondaryTimeZone?: string
  setIsKeyboardShortcutsOpen: (open: boolean) => void
  shouldSuppressEventClick?: (occurrenceId: string) => boolean
  showDragPreviewMeta: boolean
  showSecondaryTimeZone: boolean
  timeZone?: string
}

export function CalendarRootPortals({
  activeDrag,
  activeDragInteraction,
  activeDragRect,
  classNames,
  closeContextMenu,
  closeCreateSheet,
  closeEventDetails,
  closePendingEventChange,
  commitCreateEvent,
  commitEventUpdate,
  contextMenu,
  createEventSheet,
  createSheetOperation,
  density,
  detailsOccurrence,
  eventChangeConfirmation,
  eventDetails,
  eventDetailsEnabled,
  getEventColor,
  handleArchiveEvent,
  handleConfirmPendingEventChange,
  handleDeleteEvent,
  handleDuplicateEvent,
  hourCycle,
  isHydrated,
  isKeyboardShortcutsOpen,
  isPointerDragging,
  keyboardShortcuts,
  locale,
  onEventArchive,
  onEventDelete,
  onEventDuplicate,
  onEventUpdate,
  openEventDetails,
  pendingEventChange,
  renderEvent,
  renderEventDetails,
  resources,
  secondaryTimeZone,
  setIsKeyboardShortcutsOpen,
  shouldSuppressEventClick,
  showDragPreviewMeta,
  showSecondaryTimeZone,
  timeZone,
}: CalendarRootPortalsProps) {
  if (!isHydrated) {
    return null
  }

  return createPortal(
    <>
      {isPointerDragging && activeDrag?.kind === "event" && activeDragRect ? (
        <div className="pointer-events-none fixed inset-0 z-50">
          <EventSurface
            accentColor={getResolvedAccentColor(
              activeDrag.occurrence,
              getEventColor
            )}
            className={getCalendarSlotClassName(
              classNames,
              "dragOverlay",
              activeDragRect ? undefined : "w-64 max-w-[80vw]"
            )}
            density={density}
            dragging
            event={activeDrag.occurrence}
            overlay
            renderEvent={renderEvent}
            shouldSuppressClick={shouldSuppressEventClick}
            style={getDragOverlayStyle(activeDragRect, activeDragInteraction)}
            previewMetaLabel={
              showDragPreviewMeta
                ? formatDurationLabel(
                    activeDrag.occurrence.start,
                    activeDrag.occurrence.end,
                    activeDrag.occurrence.allDay
                  )
                : undefined
            }
            timeLabel={getEventMetaLabel(activeDrag.occurrence, {
              hourCycle,
              locale,
              timeZone,
            })}
            variant={activeDrag.variant}
          />
        </div>
      ) : null}
      {contextMenu ? (
        <CalendarEventContextMenu
          hourCycle={hourCycle}
          locale={locale}
          occurrence={contextMenu.occurrence}
          onArchive={
            canArchiveOccurrence(contextMenu.occurrence) && onEventArchive
              ? () => handleArchiveEvent(contextMenu.occurrence)
              : undefined
          }
          onClose={closeContextMenu}
          onDelete={
            canDeleteOccurrence(contextMenu.occurrence) && onEventDelete
              ? () => handleDeleteEvent(contextMenu.occurrence)
              : undefined
          }
          onDuplicate={
            canDuplicateOccurrence(contextMenu.occurrence) && onEventDuplicate
              ? () => handleDuplicateEvent(contextMenu.occurrence)
              : undefined
          }
          onOpenDetails={
            eventDetailsEnabled && canOpenEventDetails(contextMenu.occurrence)
              ? () => openEventDetails(contextMenu.occurrence)
              : undefined
          }
          timeZone={timeZone}
          x={contextMenu.position.x}
          y={contextMenu.position.y}
        />
      ) : null}
      <CalendarEventChangeConfirmationDialog
        config={eventChangeConfirmation}
        context={pendingEventChange}
        hourCycle={hourCycle}
        locale={locale}
        onCancel={closePendingEventChange}
        onConfirm={handleConfirmPendingEventChange}
        timeZone={timeZone}
      />
      <CalendarEventCreateSheet
        config={createEventSheet}
        initialOperation={createSheetOperation}
        onOpenChange={(open) => {
          if (!open) {
            closeCreateSheet()
          }
        }}
        onSubmit={commitCreateEvent}
        resources={resources}
        timeZone={timeZone}
      />
      <CalendarEventDetailsSheet
        config={eventDetails}
        hourCycle={hourCycle}
        locale={locale}
        occurrence={detailsOccurrence}
        onOpenChange={(open) => {
          if (!open) {
            closeEventDetails()
          }
        }}
        onSubmit={onEventUpdate ? commitEventUpdate : undefined}
        renderContent={renderEventDetails}
        resources={resources}
        secondaryTimeZone={showSecondaryTimeZone ? secondaryTimeZone : undefined}
        timeZone={timeZone}
      />
      <CalendarKeyboardShortcutsDialog
        config={keyboardShortcuts}
        onOpenChange={setIsKeyboardShortcutsOpen}
        open={isKeyboardShortcutsOpen}
      />
    </>,
    document.body
  )
}

import * as React from "react"

import { addDays, addMinutes, startOfDay } from "date-fns"

import type {
  CalendarCreateOperation,
  CalendarEvent,
  CalendarEventChangeConfirmationContext,
  CalendarDropTarget,
  CalendarOccurrence,
  CalendarResource,
  CalendarResizeOperation,
  CalendarView,
  CalendarWeekday,
} from "../../../types"
import {
  applyEventUpdateOperation,
  applyMoveOperation,
  applyResizeOperation,
  canArchiveOccurrence,
  canDeleteOccurrence,
  canDuplicateOccurrence,
  canMoveOccurrence,
  canOpenEventDetails,
  canResizeOccurrence,
  clampResize,
  formatEventTimeLabel,
  getNextVisibleDay,
  setMinuteOfDay,
  shiftDate,
} from "../../../utils"
import type {
  CalendarEventMenuPosition,
  CalendarRootProps,
} from "../../shared"

import {
  getMoveOperation,
  getResizeOperation,
} from "./root-utils"

type UseCalendarEventActionsOptions = {
  createEventSheet: CalendarRootProps["createEventSheet"]
  date: Date
  eventChangeConfirmation: CalendarRootProps["eventChangeConfirmation"]
  eventDetails: CalendarRootProps["eventDetails"]
  hourCycle?: 12 | 24
  isHydrated: boolean
  keyboardShortcuts: CalendarRootProps["keyboardShortcuts"]
  locale?: string
  minHour: number
  onDateChange: (date: Date) => void
  onEventArchive?: CalendarRootProps["onEventArchive"]
  onEventCreate?: CalendarRootProps["onEventCreate"]
  onEventDelete?: CalendarRootProps["onEventDelete"]
  onEventDuplicate?: CalendarRootProps["onEventDuplicate"]
  onEventMove?: CalendarRootProps["onEventMove"]
  onEventResize?: CalendarRootProps["onEventResize"]
  onEventSelect?: CalendarRootProps["onEventSelect"]
  onEventUpdate?: CalendarRootProps["onEventUpdate"]
  onNavigate?: CalendarRootProps["onNavigate"]
  onSelectedEventChange?: CalendarRootProps["onSelectedEventChange"]
  onToday?: CalendarRootProps["onToday"]
  optimisticEvents: CalendarEvent[]
  resolvedHiddenDays: CalendarWeekday[]
  resolvedResourceFilter: string[]
  resolvedView: CalendarView
  resources?: CalendarResource[]
  setOptimisticEvents: React.Dispatch<React.SetStateAction<CalendarEvent[]>>
  shouldBlockTimedRange: (
    start: Date,
    end: Date,
    allDay: boolean | undefined
  ) => boolean
  slotDuration: number
  timeZone?: string
}

export function useCalendarEventActions({
  createEventSheet,
  date,
  eventChangeConfirmation,
  eventDetails,
  hourCycle,
  isHydrated,
  keyboardShortcuts,
  locale,
  minHour,
  onDateChange,
  onEventArchive,
  onEventCreate,
  onEventDelete,
  onEventDuplicate,
  onEventMove,
  onEventResize,
  onEventSelect,
  onEventUpdate,
  onNavigate,
  onSelectedEventChange,
  onToday,
  optimisticEvents,
  resolvedHiddenDays,
  resolvedResourceFilter,
  resolvedView,
  resources,
  setOptimisticEvents,
  shouldBlockTimedRange,
  slotDuration,
  timeZone,
}: UseCalendarEventActionsOptions) {
  const [contextMenu, setContextMenu] = React.useState<{
    occurrence: CalendarOccurrence
    position: CalendarEventMenuPosition
  } | null>(null)
  const [pendingEventChange, setPendingEventChange] =
    React.useState<CalendarEventChangeConfirmationContext | null>(null)
  const [createSheetOperation, setCreateSheetOperation] =
    React.useState<CalendarCreateOperation | null>(null)
  const [detailsOccurrence, setDetailsOccurrence] =
    React.useState<CalendarOccurrence | null>(null)
  const [isKeyboardShortcutsOpen, setIsKeyboardShortcutsOpen] =
    React.useState(false)
  const [liveAnnouncement, setLiveAnnouncement] = React.useState("")
  const eventDetailsEnabled = eventDetails !== undefined && eventDetails !== false
  const openEventDetailsOnSelect =
    typeof eventDetails === "object" ? eventDetails.openOnSelect ?? true : true
  const keyboardShortcutsEnabled =
    keyboardShortcuts !== undefined && keyboardShortcuts !== false
  const keyboardShortcutsTrigger =
    typeof keyboardShortcuts === "object"
      ? (keyboardShortcuts.trigger ?? "both")
      : keyboardShortcutsEnabled
        ? "both"
        : null
  const keyboardShortcutsKeyTriggerEnabled =
    keyboardShortcutsTrigger === "both" || keyboardShortcutsTrigger === "?"

  const announce = React.useCallback((message: string) => {
    setLiveAnnouncement(message)
  }, [])

  React.useEffect(() => {
    if (!isHydrated || !keyboardShortcutsKeyTriggerEnabled) {
      return
    }

    function handleKeyDown(event: KeyboardEvent) {
      if (
        event.defaultPrevented ||
        event.altKey ||
        event.ctrlKey ||
        event.metaKey ||
        !(
          event.key === "?" ||
          (event.key === "/" && event.shiftKey)
        )
      ) {
        return
      }

      const target = event.target

      if (
        target instanceof HTMLElement &&
        (target.isContentEditable ||
          target.tagName === "INPUT" ||
          target.tagName === "SELECT" ||
          target.tagName === "TEXTAREA")
      ) {
        return
      }

      event.preventDefault()
      setIsKeyboardShortcutsOpen(true)
    }

    window.addEventListener("keydown", handleKeyDown)

    return () => {
      window.removeEventListener("keydown", handleKeyDown)
    }
  }, [isHydrated, keyboardShortcutsKeyTriggerEnabled])

  function formatAnnouncementRange(
    start: Date,
    end: Date,
    allDay: boolean | undefined
  ) {
    return formatEventTimeLabel(start, end, {
      allDay,
      hourCycle,
      locale,
      timeZone,
    })
  }

  function closeContextMenu() {
    setContextMenu(null)
  }

  function openEventDetails(occurrence: CalendarOccurrence) {
    if (!eventDetailsEnabled || !canOpenEventDetails(occurrence)) {
      return
    }

    closeContextMenu()
    setDetailsOccurrence(occurrence)
  }

  function closeEventDetails() {
    setDetailsOccurrence(null)
  }

  function handleSelectEvent(
    occurrence: CalendarOccurrence,
    options: {
      openDetails?: boolean
    } = {}
  ) {
    setContextMenu(null)
    onSelectedEventChange?.(occurrence.occurrenceId)
    onEventSelect?.(occurrence)

    if (options.openDetails ?? openEventDetailsOnSelect) {
      openEventDetails(occurrence)
    }
  }

  function closeCreateSheet() {
    setCreateSheetOperation(null)
  }

  function closePendingEventChange() {
    setPendingEventChange(null)
  }

  function handleOpenContextMenu(
    occurrence: CalendarOccurrence,
    position: CalendarEventMenuPosition
  ) {
    const hasActions =
      (eventDetailsEnabled && canOpenEventDetails(occurrence)) ||
      (canDuplicateOccurrence(occurrence) && !!onEventDuplicate) ||
      (canArchiveOccurrence(occurrence) && !!onEventArchive) ||
      (canDeleteOccurrence(occurrence) && !!onEventDelete)

    if (!hasActions) {
      return
    }

    handleSelectEvent(occurrence, {
      openDetails: false,
    })
    closeEventDetails()
    setContextMenu({
      occurrence,
      position,
    })
  }

  function handleNavigate(direction: -1 | 1) {
    if (onNavigate) {
      onNavigate(direction)
      return
    }

    onDateChange(shiftDate(date, resolvedView, direction, resolvedHiddenDays))
  }

  function handleToday() {
    if (onToday) {
      onToday()
      return
    }

    onDateChange(new Date())
  }

  function getDefaultCreateOperation(
    operation: CalendarCreateOperation
  ): CalendarCreateOperation {
    const defaultResource =
      resources?.find((resource) => resolvedResourceFilter.includes(resource.id)) ??
      resources?.[0]

    return {
      calendarId: operation.calendarId ?? defaultResource?.id,
      calendarLabel: operation.calendarLabel ?? defaultResource?.label,
      color: operation.color ?? defaultResource?.color,
      resourceId: operation.resourceId ?? defaultResource?.id,
      timeZone: operation.timeZone ?? timeZone,
      ...operation,
    }
  }

  function commitCreateEvent(operation: CalendarCreateOperation) {
    if (!onEventCreate) {
      return
    }

    if (shouldBlockTimedRange(operation.start, operation.end, operation.allDay)) {
      announce("Blocked time is unavailable.")
      return "Blocked time is unavailable."
    }

    onEventCreate(operation)
    onSelectedEventChange?.(undefined)
    announce(
      `Created ${operation.title ?? "a new appointment"} for ${formatAnnouncementRange(
        operation.start,
        operation.end,
        operation.allDay
      )}.`
    )
  }

  function requestEventCreate(operation: CalendarCreateOperation) {
    if (!onEventCreate) {
      return
    }

    const nextOperation = getDefaultCreateOperation(operation)

    if (
      shouldBlockTimedRange(
        nextOperation.start,
        nextOperation.end,
        nextOperation.allDay
      )
    ) {
      announce("Blocked time is unavailable.")
      return
    }

    const shouldOpenSheet =
      createEventSheet !== undefined && createEventSheet !== false

    if (shouldOpenSheet) {
      closeContextMenu()
      setCreateSheetOperation(nextOperation)
      return
    }

    commitCreateEvent(nextOperation)
  }

  function shouldConfirmEventChange(
    context: CalendarEventChangeConfirmationContext
  ) {
    if (!eventChangeConfirmation) {
      return false
    }

    if (typeof eventChangeConfirmation === "boolean") {
      return eventChangeConfirmation
    }

    return eventChangeConfirmation.shouldConfirm?.(context) ?? true
  }

  function commitEventChange(context: CalendarEventChangeConfirmationContext) {
    if (context.action === "move") {
      const operation = {
        allDay: context.allDay,
        nextEnd: context.nextEnd,
        nextStart: context.nextStart,
        occurrence: context.occurrence,
        previousEnd: context.previousEnd,
        previousStart: context.previousStart,
        scope:
          context.scope ??
          (context.occurrence.isRecurringInstance ? "series" : "occurrence"),
      } as const

      setOptimisticEvents((currentEvents) =>
        applyMoveOperation(currentEvents, operation)
      )
      onEventMove?.(operation)
      announce(
        `Moved ${context.occurrence.title} to ${formatAnnouncementRange(
          context.nextStart,
          context.nextEnd,
          context.allDay ?? context.occurrence.allDay
        )}.`
      )
      return
    }

    const operation = {
      edge: context.edge,
      nextEnd: context.nextEnd,
      nextStart: context.nextStart,
      occurrence: context.occurrence,
      previousEnd: context.previousEnd,
      previousStart: context.previousStart,
      scope:
        context.scope ??
        (context.occurrence.isRecurringInstance ? "series" : "occurrence"),
    } as const

    setOptimisticEvents((currentEvents) =>
      applyResizeOperation(currentEvents, operation)
    )
    onEventResize?.(operation)
    announce(
      `Resized ${context.occurrence.title} to ${formatAnnouncementRange(
        context.nextStart,
        context.nextEnd,
        context.occurrence.allDay
      )}.`
    )
  }

  function commitEventUpdate(nextEvent: CalendarEvent) {
    if (!detailsOccurrence || !onEventUpdate) {
      return
    }

    const previousEvent =
      optimisticEvents.find((event) => event.id === detailsOccurrence.sourceEventId) ??
      {
        ...detailsOccurrence,
        id: detailsOccurrence.sourceEventId,
      }
    const operation = {
      occurrence: detailsOccurrence,
      nextEvent,
      previousEvent,
      scope: detailsOccurrence.isRecurringInstance ? "series" : "occurrence",
    } as const

    setOptimisticEvents((currentEvents) =>
      applyEventUpdateOperation(currentEvents, operation)
    )
    setDetailsOccurrence((currentOccurrence) =>
      currentOccurrence
        ? {
            ...currentOccurrence,
            ...nextEvent,
            occurrenceId: currentOccurrence.occurrenceId,
            sourceEventId: currentOccurrence.sourceEventId,
          }
        : currentOccurrence
    )
    onEventUpdate(operation)
    announce(
      `Updated ${nextEvent.title} to ${formatAnnouncementRange(
        nextEvent.start,
        nextEvent.end,
        nextEvent.allDay
      )}.`
    )
  }

  function requestEventChange(
    context: CalendarEventChangeConfirmationContext
  ) {
    closeContextMenu()

    const allDay =
      context.action === "move"
        ? context.allDay ?? context.occurrence.allDay
        : context.occurrence.allDay

    if (shouldBlockTimedRange(context.nextStart, context.nextEnd, allDay)) {
      announce("Blocked time is unavailable.")
      return
    }

    if (shouldConfirmEventChange(context)) {
      setPendingEventChange(context)
      return
    }

    commitEventChange(context)
  }

  function handleQuickCreate() {
    if (!onEventCreate) {
      return
    }

    const quickCreateDay = getNextVisibleDay(date, resolvedHiddenDays)
    const start = setMinuteOfDay(
      startOfDay(quickCreateDay),
      Math.max(minHour * 60, 9 * 60)
    )

    requestEventCreate({
      start,
      end: addMinutes(start, 60),
    })
  }

  function moveOccurrenceWithTarget(
    occurrence: CalendarOccurrence,
    target: CalendarDropTarget,
    dragOffsetMinutes = 0
  ) {
    if (!onEventMove || !canMoveOccurrence(occurrence)) {
      return
    }

    const operation = getMoveOperation(occurrence, target, dragOffsetMinutes)
    requestEventChange({
      action: "move",
      ...operation,
    })
  }

  function resizeOccurrenceWithTarget(
    occurrence: CalendarOccurrence,
    edge: "start" | "end",
    target: CalendarDropTarget
  ) {
    if (!onEventResize || !canResizeOccurrence(occurrence)) {
      return
    }

    const operation = getResizeOperation(occurrence, edge, target, slotDuration)
    requestEventChange({
      action: "resize",
      ...operation,
    })
  }

  function handleDuplicateEvent(occurrence: CalendarOccurrence) {
    if (!canDuplicateOccurrence(occurrence)) {
      announce("This event cannot be duplicated.")
      return
    }

    onEventDuplicate?.(occurrence)
    onSelectedEventChange?.(undefined)
    closeContextMenu()
    closeEventDetails()
    announce(`Duplicated ${occurrence.title}.`)
  }

  function handleArchiveEvent(occurrence: CalendarOccurrence) {
    if (!canArchiveOccurrence(occurrence)) {
      announce("This event cannot be archived.")
      return
    }

    onEventArchive?.(occurrence)
    onSelectedEventChange?.(undefined)
    closeContextMenu()
    closeEventDetails()
    announce(`Archived ${occurrence.title}.`)
  }

  function handleDeleteEvent(occurrence: CalendarOccurrence) {
    if (!canDeleteOccurrence(occurrence)) {
      announce("This event cannot be deleted.")
      return
    }

    onEventDelete?.(occurrence)
    onSelectedEventChange?.(undefined)
    closeContextMenu()
    closeEventDetails()
    announce(`Deleted ${occurrence.title}.`)
  }

  function handleConfirmPendingEventChange() {
    if (!pendingEventChange) {
      return
    }

    commitEventChange(pendingEventChange)
    closePendingEventChange()
  }

  function handleEventKeyCommand(
    occurrence: CalendarOccurrence,
    event: React.KeyboardEvent<HTMLButtonElement>
  ) {
    const dayDelta =
      event.key === "ArrowLeft" ? -1 : event.key === "ArrowRight" ? 1 : 0
    const minuteDelta =
      event.key === "ArrowUp"
        ? -slotDuration
        : event.key === "ArrowDown"
          ? slotDuration
          : 0

    if (dayDelta === 0 && minuteDelta === 0) {
      return
    }

    event.preventDefault()

    if (event.shiftKey && onEventResize) {
      if (!canResizeOccurrence(occurrence)) {
        announce("This event cannot be resized.")
        return
      }

      const operation: CalendarResizeOperation = {
        occurrence,
        edge: "end",
        nextStart: occurrence.start,
        nextEnd: clampResize(
          addMinutes(addDays(occurrence.end, dayDelta), minuteDelta),
          occurrence.start,
          "end",
          slotDuration
        ),
        previousStart: occurrence.start,
        previousEnd: occurrence.end,
        scope: occurrence.isRecurringInstance ? "series" : "occurrence",
      }

      requestEventChange({
        action: "resize",
        ...operation,
      })
      return
    }

    if (event.altKey && onEventResize) {
      if (!canResizeOccurrence(occurrence)) {
        announce("This event cannot be resized.")
        return
      }

      const operation: CalendarResizeOperation = {
        occurrence,
        edge: "start",
        nextStart: clampResize(
          addMinutes(addDays(occurrence.start, dayDelta), minuteDelta),
          occurrence.end,
          "start",
          slotDuration
        ),
        nextEnd: occurrence.end,
        previousStart: occurrence.start,
        previousEnd: occurrence.end,
        scope: occurrence.isRecurringInstance ? "series" : "occurrence",
      }

      requestEventChange({
        action: "resize",
        ...operation,
      })
      return
    }

    if (!onEventMove || !canMoveOccurrence(occurrence)) {
      announce("This event cannot be moved.")
      return
    }

    const operation = {
      occurrence,
      nextStart: addMinutes(addDays(occurrence.start, dayDelta), minuteDelta),
      nextEnd: addMinutes(addDays(occurrence.end, dayDelta), minuteDelta),
      previousStart: occurrence.start,
      previousEnd: occurrence.end,
      allDay: occurrence.allDay,
      scope: occurrence.isRecurringInstance ? "series" : "occurrence",
    } as const

    requestEventChange({
      action: "move",
      ...operation,
    })
  }

  return {
    announce,
    closeContextMenu,
    closeCreateSheet,
    closeEventDetails,
    closePendingEventChange,
    commitCreateEvent,
    commitEventUpdate,
    contextMenu,
    createSheetOperation,
    detailsOccurrence,
    eventDetailsEnabled,
    handleArchiveEvent,
    handleConfirmPendingEventChange,
    handleDeleteEvent,
    handleDuplicateEvent,
    handleEventKeyCommand,
    handleNavigate,
    handleOpenContextMenu,
    handleQuickCreate,
    handleSelectEvent,
    handleToday,
    isKeyboardShortcutsOpen,
    keyboardShortcutsKeyTriggerEnabled,
    keyboardShortcutsEnabled,
    liveAnnouncement,
    moveOccurrenceWithTarget,
    openEventDetails,
    openEventDetailsOnSelect,
    pendingEventChange,
    requestEventCreate,
    resizeOccurrenceWithTarget,
    setDetailsOccurrence,
    setIsKeyboardShortcutsOpen,
  }
}
